detailed_optimizations.code_changes:
1) 给数组指针加 restrict（或在函数签名中使用 __restrict__）并确保对齐（posix_memalign/PolyBench 对齐宏）。
2) 将二维下标提升为行指针，减少乘法寻址。
3) 加 OpenMP 并行与 SIMD 指令提示。
示例（核心片段）：
```c
void kernel_fdtd_2d(...,
  DATA_TYPE (* __restrict__ ex)[NY],
  DATA_TYPE (* __restrict__ ey)[NY],
  DATA_TYPE (* __restrict__ hz)[NY],
  DATA_TYPE * __restrict__ _fict_)
{
  for (int t=0; t<_PB_TMAX; t++) {
    #pragma omp parallel for simd
    for (int j=0; j<_PB_NY; j++) ey[0][j] = _fict_[t];

    #pragma omp parallel for collapse(2)
    for (int i=1; i<_PB_NX; i++) {
      DATA_TYPE * __restrict__ eyi = ey[i];
      DATA_TYPE * __restrict__ hzi = hz[i];
      DATA_TYPE * __restrict__ hzim1 = hz[i-1];
      #pragma omp simd
      for (int j=0; j<_PB_NY; j++) {
        eyi[j] = eyi[j] - (DATA_TYPE)0.5 * (hzi[j] - hzim1[j]);
      }
    }
    ...
  }
}
```

1) 将 j=1..NY-1 主体与 j=0 边界分离（当前已从 1 开始，保持）。
2) 行指针提升 + #pragma omp simd。
3) 若编译器支持且确认写不再被读取，可尝试 non-temporal store（谨慎：ex 在同一 t 的 hz 更新会读取 ex[i][j] 与 ex[i][j+1]，因此对 ex 的写通常会很快被读取，不适合流式写）。
示例：
```c
#pragma omp parallel for collapse(2)
for (int i=0; i<_PB_NX; i++) {
  DATA_TYPE * __restrict__ exi = ex[i];
  DATA_TYPE * __restrict__ hzi = hz[i];
  #pragma omp simd
  for (int j=1; j<_PB_NY; j++) {
    exi[j] = exi[j] - (DATA_TYPE)0.5 * (hzi[j] - hzi[j-1]);
  }
}
```

关键点：hz 更新读取 ex[i][j], ex[i][j+1], ey[i][j], ey[i+1][j]，这些数据刚在同一 t 的前两段循环写入。若数组很大，写入后很快被逐出缓存，会导致 hz 阶段再次从内存读回，带宽压力翻倍。

做法 A（推荐，通用 CPU）：对 i/j 做块划分，使 ex/ey 的“刚写数据”在缓存中被 hz 阶段消费。
```c
const int BI=32, BJ=256; // 需按 L2/L3 与 NY 调参
for (int t=0; t<_PB_TMAX; t++) {
  #pragma omp parallel for
  for (int j=0; j<_PB_NY; j++) ey[0][j]=_fict_[t];

  for (int ii=1; ii<_PB_NX; ii+=BI) {
    int iend = (ii+BI<_PB_NX)? ii+BI : _PB_NX;
    for (int jj=0; jj<_PB_NY; jj+=BJ) {
      int jend = (jj+BJ<_PB_NY)? jj+BJ : _PB_NY;

      // ey tile
      #pragma omp parallel for collapse(2)
      for (int i=ii; i<iend; i++) {
        DATA_TYPE *eyi=ey[i]; DATA_TYPE *hzi=hz[i]; DATA_TYPE *hzim1=hz[i-1];
        #pragma omp simd
        for (int j=jj; j<jend; j++) eyi[j] -= (DATA_TYPE)0.5*(hzi[j]-hzim1[j]);
      }

      // ex tile (note j starts at 1)
      #pragma omp parallel for collapse(2)
      for (int i=ii-1; i<iend; i++) { // include ii-1 row because hz uses ey[i+1]
        if (i<0 || i>=_PB_NX) continue;
        DATA_TYPE *exi=ex[i]; DATA_TYPE *hzi=hz[i];
        int js = (jj==0)? 1 : jj;
        #pragma omp simd
        for (int j=js; j<jend; j++) exi[j] -= (DATA_TYPE)0.5*(hzi[j]-hzi[j-1]);
      }

      // hz tile consumes fresh ex/ey
      #pragma omp parallel for collapse(2)
      for (int i=ii-1; i<iend-1; i++) {
        if (i<0) continue;
        DATA_TYPE *hzi=hz[i]; DATA_TYPE *exi=ex[i]; DATA_TYPE *eyi=ey[i]; DATA_TYPE *eyip1=ey[i+1];
        int je = (jend==_PB_NY)? _PB_NY-1 : jend;
        #pragma omp simd
        for (int j=jj; j<je; j++) {
          hzi[j] -= (DATA_TYPE)0.7 * ( (exi[j+1]-exi[j]) + (eyip1[j]-eyi[j]) );
        }
      }
    }
  }
}
```
做法 B（更激进）：在小 tile 内融合 ex/ey/hz 的计算顺序以最大化 L1/L2 复用，但要小心边界与依赖（hz 需要 ex 的 j+1 与 ey 的 i+1）。
